#!/usr/bin/env bash
set -euo pipefail; set -a; . /etc/greentree/greentree.env; set +a; : "${TELEGRAM_BOT_TOKEN:?}" "${TELEGRAM_WEBHOOK_SECRET:?}" "${TELEGRAM_WEBHOOK_URL:?}"; api="https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}"; curl -fsS -X POST "$api/setWebhook" -d "url=$TELEGRAM_WEBHOOK_URL" -d "secret_token=$TELEGRAM_WEBHOOK_SECRET" -d 'allowed_updates=["message","callback_query"]' >/dev/null; curl -fsS -X POST "$api/setMyCommands" --data-urlencode 'commands=[{"command":"start","description":"Open Green Tree"},{"command":"buy","description":"Buy GTREE"},{"command":"price","description":"Live price"},{"command":"activity","description":"Recent activity"},{"command":"support","description":"Contact support"},{"command":"status","description":"Service status"},{"command":"help","description":"Help"},{"command":"cancel","description":"Cancel"}]' >/dev/null; curl -fsS "$api/getWebhookInfo" | node -e 'let x="";process.stdin.on("data",d=>x+=d).on("end",()=>{let j=JSON.parse(x);if(!j.ok)process.exit(1);console.log(JSON.stringify({url:j.result.url,pending_update_count:j.result.pending_update_count,last_error_date:j.result.last_error_date??null}))})'
